{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스를 목표로 한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "mismatch 발생 시 먼저 패키지 설정을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 스크립트 수정을 검토한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표이며 확정 공개 릴리스 결정이 아님",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토",
        "note": "의견 제시만 있었고 담당자 확정 없음",
        "certainty": "confirmed"
      },
      {
        "item": "Hara의 tarball 경로 확인 시점",
        "note": "Minjun의 스모크 결과 공유 이후 수행, 정확한 마감시각 미정",
        "certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로 오류로 릴리스 지연 가능",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자 오도 가능",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "unresolved"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?",
        "status": "unresolved"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "Friday 10:00 KST",
      "status": "planned",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "Friday 12:00 KST",
      "status": "planned",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 확인",
      "due": "미정 (결과 공유 이후)",
      "status": "planned",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계 검토(가능하면 목요일)",
      "due": "Thursday (if possible)",
      "status": "owner_unassigned",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 스모크 테스트 결과 수신 여부 확인",
      "금요일 12:00 KST까지 action_items.md 트리아지 노트 작성 여부 확인",
      "스모크 결과 공유 직후 tarball 경로 검증 결과 확인",
      "최종 릴리스 승인 권한자 지정",
      "릴리스 노트에 수요일 내부 스트레치 목표 언급 여부 결정"
    ],
    "do_not_invent": [
      "고객명/외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 owner",
      "미확정 deadline"
    ]
  },
  "non_invention_rules": {
    "scope_rule": "인라인 공개-안전 합성 픽스처에 명시된 사실만 사용한다.",
    "fact_boundary": [
      "확정되지 않은 항목은 결정으로 기록하지 않는다.",
      "거절된 제안은 별도 구역에 분리한다.",
      "내부 스트레치 목표와 확정 공개 목표를 혼합하지 않는다."
    ],
    "explicit_non_facts": [
      "고객명 없음",
      "예산 언급 없음",
      "보안 사고 없음",
      "프로덕션 장애 없음",
      "법무 승인 요건 언급 없음"
    ]
  }
}
